// Parse Anthropic node response
// Native n8n Anthropic node returns: { text: '...' }
// HTTP fallback returns: { content: [{ type: 'text', text: '...' }] }
const response = $input.first().json;
const rawText = response.text || response.content?.[0]?.text || '{}';

let classification;
try {
  const cleaned = rawText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  classification = JSON.parse(cleaned);
} catch (e) {
  classification = {
    company_name: 'Unknown',
    sender_domain: 'unknown',
    doc_type: 'email_body',
    deal_indicators: [],
    guessed_deal_company: 'Unknown',
    confidence: 'low',
    confidence_score: 0.1,
    reasoning: 'Parse error: ' + e.message
  };
}

// Get original email data
// Gmail node exposes headers as TOP-LEVEL Pascal-case keys: From, Subject, To, Date
// (not lowercase, not in payload.headers array which may be truncated)
const emailData = $('Gmail: Get Full Message').first().json;

// Helper: extract a header value from raw Gmail payload.headers array
function getHeader(headers, name) {
  if (!headers) return '';
  const h = headers.find(h => h.name.toLowerCase() === name.toLowerCase());
  return h ? h.value : '';
}

const headers = emailData.payload?.headers || [];
// Check Pascal-case top-level (confirmed), lowercase fallback, then payload.headers array
const senderEmail = emailData.From || emailData.from || getHeader(headers, 'From') || '';
const subject = emailData.Subject || emailData.subject || getHeader(headers, 'Subject') || '';
const emailDate = emailData.Date || emailData.date || getHeader(headers, 'Date') || new Date().toISOString();

// Extract domain from sender email (handles 'Name <email@domain.com>' format)
function extractDomain(emailStr) {
  const match = emailStr.match(/<([^>]+)>/) || emailStr.match(/([^\s]+)/);
  const addr = match ? match[1] : emailStr;
  const parts = addr.split('@');
  return parts.length === 2 ? parts[1].toLowerCase() : 'unknown';
}
const resolvedDomain = extractDomain(senderEmail) || classification.sender_domain || 'unknown';

// Extract full body text from Gmail payload
// Gmail returns body in different places depending on email structure:
// - Simple text email: emailData.text (n8n surfaces it) OR payload.body.data (base64)
// - multipart/alternative: body is in payload.parts[*].body.data (base64, mimeType=text/plain)
// - snippet is only ~200 chars — never use it as the body
function decodeBase64(str) {
  if (!str) return '';
  // Gmail uses URL-safe base64 (replace - with + and _ with /)
  const standard = str.replace(/-/g, '+').replace(/_/g, '/');
  try {
    return Buffer.from(standard, 'base64').toString('utf-8');
  } catch(e) {
    return '';
  }
}

function extractTextFromParts(parts) {
  if (!parts || !Array.isArray(parts)) return '';
  for (const part of parts) {
    if (part.mimeType === 'text/plain' && part.body?.data) {
      return decodeBase64(part.body.data);
    }
    // Recurse into nested multipart
    if (part.parts) {
      const nested = extractTextFromParts(part.parts);
      if (nested) return nested;
    }
  }
  return '';
}

let fullText = emailData.text || '';
if (!fullText || fullText.length < 200) {
  // Try payload.body.data (simple emails)
  const bodyData = emailData.payload?.body?.data;
  if (bodyData) fullText = decodeBase64(bodyData);
}
if (!fullText || fullText.length < 200) {
  // Try payload.parts (multipart emails)
  fullText = extractTextFromParts(emailData.payload?.parts || []);
}
if (!fullText) fullText = emailData.snippet || '';

return [{
  json: {
    ...classification,
    sender_domain: resolvedDomain,
    message_id: emailData.id,
    subject: subject,
    sender_email: senderEmail,
    email_date: emailDate,
    text: fullText,
    html: emailData.html || '',
    attachments: emailData.payload?.parts?.filter(p => p.filename && p.filename.length > 0) || []
  }
}];

// Low-confidence emails still get ingested — just tagged as 'unattributed'
// so they're searchable once Austin confirms the deal in the attribution queue.
const emailData = $('Code: Parse Classification').first().json;
return [{
  json: {
    ...emailData,
    deal_id: 'unattributed',
    qdrant_namespace: 'unattributed',
    attribution_confidence: 'low',
    is_new_deal: false,
    company_name: emailData.guessed_deal_company || emailData.company_name || 'Unknown'
  }
}];

// Build deal_id from matched deal or generate a slug
// Always pull email data from Parse Classification (upstream of Postgres lookup)
const emailData = $('Code: Parse Classification').first().json;
const dealLookup = $('Postgres: Lookup Deal (High)').first()?.json;

let deal_id = dealLookup?.deal_id;
if (!deal_id) {
  const company = (emailData.guessed_deal_company || emailData.company_name || 'unknown')
    .toLowerCase()
    .replace(/[^a-z0-9]/g, '_')
    .replace(/_+/g, '_')
    .substring(0, 32);
  const year = new Date().getFullYear();
  deal_id = `cw_${company}_${year}`;
}

// If new deal (not found in deals table), insert it
const isNewDeal = !dealLookup?.deal_id;

return [{
  json: {
    ...emailData,
    deal_id,
    qdrant_namespace: deal_id,
    attribution_confidence: emailData.confidence,
    is_new_deal: isNewDeal,
    company_name: dealLookup?.company_name || emailData.company_name || emailData.guessed_deal_company
  }
}];

// Extract clean text from email body
const emailData = $input.first().json;

let text = emailData.text || emailData.snippet || '';

if (!text && emailData.html) {
  text = emailData.html
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/\s+/g, ' ')
    .trim();
}

const boilerplate = [
  /CONFIDENTIALITY NOTICE[\s\S]*?$/i,
  /This email and any attachments[\s\S]*?$/i,
  /DISCLAIMER[\s\S]*?$/i,
  /Sent from my iPhone/i,
  /Get Outlook for/i
];
for (const p of boilerplate) { text = text.replace(p, ''); }

return [{ json: { ...emailData, extracted_text: text.trim(), extraction_method: 'email_body' } }];

// Parse thread: split a forwarded/reply email thread into individual messages.
// Each message gets its own sender, date, and body — so Qdrant gets accurate timestamps.
// Falls back to treating the whole body as a single message if no thread structure detected.

const data = $input.first().json;
const rawText = data.extracted_text || data.text || '';

// --- Thread splitter patterns (Gmail, Outlook, Apple Mail) ---
// Pattern 1: Gmail forwarded message header
//   ---------- Forwarded message ---------
//   From: Name <email>
//   Date: Wed, Jan 21, 2026 at 5:50 PM
const GMAIL_FWD = /^-{5,}\s*Forwarded message\s*-{5,}\s*$/im;

// Pattern 2: Gmail/Outlook reply quote header
//   On Wed, Jan 21, 2026 at 5:50 PM Austin Holland <austin@...> wrote:
const REPLY_HEADER = /^On\s+\w{3},?\s+\w+\s+\d+,\s+\d{4}\s+at\s+[\d:]+\s*(AM|PM).*wrote:\s*$/im;

// Pattern 3: Outlook forwarded block
//   From: Name <email>
//   Sent: Wednesday, January 21, 2026 5:50 PM
//   To: ...
//   Subject: ...
const OUTLOOK_FWD = /^From:\s*.+\r?\nSent:\s*.+\r?\nTo:\s*/im;

// Helper: extract From/Date from a header block
function parseHeaders(block) {
  const fromMatch = block.match(/From:\s*([^\n\r]+)/i);
  const dateMatch = block.match(/(?:Date|Sent):\s*([^\n\r]+)/i);
  const fromRaw = fromMatch ? fromMatch[1].trim() : '';
  const dateRaw = dateMatch ? dateMatch[1].trim() : '';

  // Extract email address from 'Name <email>' or bare email
  const emailMatch = fromRaw.match(/<([^>]+)>/) || fromRaw.match(/(\S+@\S+)/);
  const senderEmail = emailMatch ? emailMatch[1] : fromRaw;

  // Parse date — JS Date handles most formats gracefully
  let dateCreated = data.email_date || new Date().toISOString();
  if (dateRaw) {
    const parsed = new Date(dateRaw);
    if (!isNaN(parsed.getTime())) dateCreated = parsed.toISOString();
  }

  return { senderEmail, dateCreated };
}

// --- Split logic ---
let messages = [];

// Try to split on Gmail forwarded header
if (GMAIL_FWD.test(rawText)) {
  const parts = rawText.split(GMAIL_FWD);
  for (const part of parts) {
    const trimmed = part.trim();
    if (!trimmed) continue;
    const { senderEmail, dateCreated } = parseHeaders(trimmed);
    // Strip the header lines, keep the body
    const body = trimmed.replace(/^(From:|Date:|To:|Cc:|Subject:)[^\n]*\n/gim, '').trim();
    if (body.length > 50) messages.push({ senderEmail, dateCreated, body });
  }
}

// Try reply-quote headers if no forwarded splits found
if (messages.length <= 1) {
  const parts = rawText.split(REPLY_HEADER);
  if (parts.length > 1) {
    messages = [];
    for (const part of parts) {
      const trimmed = part.trim();
      if (!trimmed) continue;
      // Reply headers appear as separators — try to parse date from preceding line
      const { senderEmail, dateCreated } = parseHeaders(trimmed);
      const body = trimmed.replace(/^On\s+[^\n]+wrote:/im, '').trim();
      if (body.length > 50) messages.push({ senderEmail, dateCreated, body });
    }
  }
}

// Try Outlook forwarded block
if (messages.length <= 1 && OUTLOOK_FWD.test(rawText)) {
  const parts = rawText.split(/(?=^From:\s*.+\r?\nSent:\s*)/im);
  if (parts.length > 1) {
    messages = [];
    for (const part of parts) {
      const trimmed = part.trim();
      if (!trimmed) continue;
      const { senderEmail, dateCreated } = parseHeaders(trimmed);
      const body = trimmed.replace(/^(From:|Sent:|To:|Cc:|Subject:)[^\n]*\n/gim, '').trim();
      if (body.length > 50) messages.push({ senderEmail, dateCreated, body });
    }
  }
}

// Fallback: single message, no thread detected
if (messages.length === 0) {
  messages = [{ senderEmail: data.sender_email || '', dateCreated: data.email_date || new Date().toISOString(), body: rawText }];
}

// Sort chronologically (oldest first)
messages.sort((a, b) => new Date(a.dateCreated) - new Date(b.dateCreated));

// Return one item per message, carrying all deal metadata but overriding sender/date per message
return messages.map((msg, i) => ({
  json: {
    ...data,
    extracted_text: msg.body,
    sender_email: msg.senderEmail || data.sender_email,
    email_date: msg.dateCreated,
    thread_index: i,
    thread_total: messages.length,
    // Preserve original message_id but make each thread message unique for dedup
    message_id: messages.length > 1 ? `${data.message_id}_t${i}` : data.message_id
  }
}));

// Merge extracted text with email metadata
const emailData = $input.first().json;
const extractedText = emailData.extracted_text || emailData.text || emailData.snippet || '';

return [{ json: { ...emailData, extracted_text: extractedText } }];

// Contextual enrichment: prepend deal/doc context to extracted text
const data = $input.first().json;

// For calendar invites, embeddable_text is already built by Code: Parse ICS
if (data.doc_type === 'calendar_invite' && data.embeddable_text) {
  return [{ json: { ...data, enriched_text: data.embeddable_text, extracted_text: data.embeddable_text } }];
}

const dealId = data.deal_id || 'unknown';
const companyName = data.company_name || data.guessed_deal_company || 'Unknown Company';
const docType = data.doc_type || 'email';
const senderEmail = data.sender_email || '';
const rawText = data.extracted_text || '';

// For call transcripts, try to extract the actual call date from the document content.
// Transcripts are often forwarded days after the call occurred, so the Gmail Date header
// reflects when the email was sent, not when the call happened.
// Look for common transcript date patterns at the top of the document.
function extractTranscriptDate(text) {
  // Match patterns like:
  //   Date: January 21, 2026
  //   Date: 2026-01-21
  //   Call Date: Wed, Jan 21, 2026
  //   January 21, 2026  (standalone line near top)
  const patterns = [
    /^(?:call\s+)?date[:\s]+([\w,\s]+\d{4})/im,
    /^date[:\s]+(\d{4}-\d{2}-\d{2})/im,
    /^(?:meeting|session|call)[\s\S]{0,40}?(\b(?:january|february|march|april|may|june|july|august|september|october|november|december)\s+\d{1,2},?\s+\d{4})/im,
    /\b(\d{4}-\d{2}-\d{2})\b/,
    /\b((?:january|february|march|april|may|june|july|august|september|october|november|december)\s+\d{1,2},?\s+\d{4})\b/i
  ];
  // Only scan the first 500 chars — date lines are always near the top
  const sample = text.slice(0, 500);
  for (const pattern of patterns) {
    const match = sample.match(pattern);
    if (match) {
      const parsed = new Date(match[1]);
      if (!isNaN(parsed.getTime())) return parsed.toISOString();
    }
  }
  return null;
}

let resolvedDate = data.email_date;
if (docType === 'call_transcript') {
  const transcriptDate = extractTranscriptDate(rawText);
  if (transcriptDate) resolvedDate = transcriptDate;
}

const emailDate = resolvedDate ? new Date(resolvedDate).toISOString().split('T')[0] : new Date().toISOString().split('T')[0];

const contextHeader = `[DEAL CONTEXT]\nDeal: ${companyName} (ID: ${dealId})\nDocument Type: ${docType}\nDate: ${emailDate}\nSource: ${senderEmail}\n[END CONTEXT]\n\n`;

const enrichedText = contextHeader + rawText;

return [{ json: { ...data, enriched_text: enrichedText, email_date: resolvedDate || data.email_date } }];

// Split enriched text into chunks, carrying all deal metadata forward.
// call_transcript: sentence-boundary aware, chunkSize=2500, overlap=250
//   — keeps full speaker utterances intact so CAS-scoring evidence
//     (e.g. "I would stagegate this...") never splits across chunks.
// All other doc types: fixed character split, chunkSize=1800, overlap=180
const data = $input.first().json;
const text = data.enriched_text || '';
const isTranscript = (data.doc_type === 'call_transcript');
const chunkSize    = isTranscript ? 2500 : 1800;
const chunkOverlap = isTranscript ? 250  : 180;

let chunks = [];

if (isTranscript) {
  // Sentence-boundary aware splitting for transcripts.
  // Split on sentence-ending punctuation OR speaker-turn boundaries ("Name: ").
  // Regex: split AFTER . ? ! followed by whitespace+capital, OR at a newline
  // followed by a word and colon (speaker label like "Austin:" or "Brad:").
  const sentenceBreak = /(?<=[.?!])\s+(?=[A-Z])|(?=\n[A-Za-z][^:\n]{0,30}:)/g;
  const sentences = text.split(sentenceBreak).filter(s => s.trim().length > 0);

  let current = '';
  for (const sentence of sentences) {
    if (current.length + sentence.length > chunkSize && current.length > 0) {
      chunks.push(current.trim());
      // Overlap: keep the tail of the current chunk as the start of the next
      const overlapStart = current.length > chunkOverlap
        ? current.length - chunkOverlap
        : 0;
      current = current.slice(overlapStart) + ' ' + sentence;
    } else {
      current += (current.length > 0 ? ' ' : '') + sentence;
    }
  }
  if (current.trim().length > 0) chunks.push(current.trim());

} else {
  // Fixed character split for emails, PDFs, and everything else
  let start = 0;
  while (start < text.length) {
    const end = Math.min(start + chunkSize, text.length);
    chunks.push(text.slice(start, end));
    if (end === text.length) break;
    start = end - chunkOverlap;
  }
}

return chunks.map((chunk, index) => ({
  json: {
    ...data,
    chunk_text: chunk,
    chunk_index: index,
    total_chunks: chunks.length
  }
}));

// Build Qdrant point with embedding + full metadata payload
// HTTP Request nodes break paired item chains in n8n — retrieve chunk data
// by matching on chunk_index from all Code: Chunk Text outputs.
const allItems = $input.all();
const allChunks = $('Code: Chunk Text').all();

// UUID v4 without require('crypto') — n8n sandbox blocks it
function uuidv4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
  });
}

// Build one point per item in input (each is one OpenAI embed response)
return allItems.map((item, i) => {
  const embedding = item.json.data?.[0]?.embedding;
  if (!embedding) throw new Error(`No embedding at index ${i}`);
  // Match chunk by index — allChunks and allItems are in the same order
  const chunkData = (allChunks[i] || allChunks[0]).json;
  const point = {
    id: uuidv4(),
    vector: embedding,
    payload: {
      deal_id: chunkData.deal_id || 'unknown',
      company_name: chunkData.company_name || chunkData.guessed_deal_company || 'Unknown',
      doc_type: chunkData.doc_type || 'email_body',
      sender_domain: chunkData.sender_domain || '',
      attribution_confidence: chunkData.attribution_confidence || 'low',
      date_created: chunkData.email_date || '',
      message_id: chunkData.message_id || '',
      chunk_index: chunkData.chunk_index || i,
      page_content: chunkData.chunk_text || ''
    }
  };
  return { json: { point, ...chunkData } };
});

// Pull deal metadata from the attribution node (Postgres: Upsert Deal outputs {success:true})
// Use Code: Assign Deal ID as the source of truth for deal metadata
let dealData;
try {
  dealData = $('Code: Assign Deal ID').first().json;
} catch(e) {
  dealData = $('Code: Assign Unattributed Deal ID').first().json;
}
return [{ json: dealData }];

// Count how many chunks were upserted into Qdrant.
// $input.first().json here is the Qdrant API response — not chunk metadata.
// Code: Build Qdrant Point spreads ...chunkData (with message_id, deal_id, etc.)
// so we pull directly from that node by name.
const enrichData = $('Code: Build Qdrant Point').first().json;
const chunkCount = enrichData.total_chunks || $('Code: Build Qdrant Point').all().length;
return [{ json: { ...enrichData, chunk_count: chunkCount } }];

// Normalise email fields for content-level dedup
// Strips FW:/Re:/Fwd: prefix from subject so forwarded copies are caught
const msg = $input.first().json;

function getHeader(headers, name) {
  if (!headers) return '';
  const h = headers.find(h => h.name.toLowerCase() === name.toLowerCase());
  return h ? h.value : '';
}
const headers = msg.payload?.headers || [];
const rawSubject = msg.Subject || msg.subject || getHeader(headers, 'Subject') || '';
const rawFrom    = msg.From    || msg.from    || getHeader(headers, 'From')    || '';

// Strip reply/forward prefixes recursively
const normSubject = rawSubject.replace(/^(fw:|re:|fwd:|forward:)\s*/gi, '').trim().toLowerCase();

// Extract domain from From header  'Name <email@domain.com>' or 'email@domain.com'
const addrMatch = rawFrom.match(/<([^>]+)>/) || rawFrom.match(/(\S+@\S+)/);
const senderAddr = addrMatch ? addrMatch[1] : rawFrom;
const domain = senderAddr.includes('@') ? senderAddr.split('@')[1].toLowerCase().replace(/['>]/g,'') : '';

return [{ json: { ...msg, norm_subject: normSubject, sender_domain_dedup: domain } }];

// Parse .ics calendar invite from Gmail attachment or email body
const emailData = $('Gmail: Get Full Message').first().json;
const dealData = $('Code: Pass Deal Data').first().json;

let icsText = '';

function findIcsInParts(parts) {
  if (!parts) return '';
  for (const part of parts) {
    const mime = part.mimeType || '';
    const filename = part.filename || '';
    if (mime === 'text/calendar' || filename.endsWith('.ics')) {
      const data = part.body?.data || '';
      if (data) return Buffer.from(data.replace(/-/g,'+').replace(/_/g,'/'), 'base64').toString('utf8');
    }
    if (part.parts) {
      const found = findIcsInParts(part.parts);
      if (found) return found;
    }
  }
  return '';
}
icsText = findIcsInParts(emailData.payload?.parts || []);

if (!icsText) {
  try {
    const fetched = $input.first().json;
    if (fetched && fetched.data) {
      icsText = Buffer.from(fetched.data.replace(/-/g,'+').replace(/_/g,'/'), 'base64').toString('utf8');
    }
  } catch(e) {}
}

if (!icsText) {
  const body = emailData.text || emailData.snippet || '';
  if (body.includes('BEGIN:VCALENDAR')) icsText = body;
}

if (!icsText && $input.first().binary) {
  const binaryKeys = Object.keys($input.first().binary || {});
  for (const key of binaryKeys) {
    const b = $input.first().binary[key];
    if (b.mimeType === 'text/calendar' || (b.fileName || '').endsWith('.ics')) {
      icsText = Buffer.from(b.data, 'base64').toString('utf8');
      break;
    }
  }
}

if (!icsText) {
  throw new Error('No ICS content found in email');
}

function unfoldICS(text) {
  return text.replace(/\r\n[ \t]/g, '').replace(/\n[ \t]/g, '');
}
icsText = unfoldICS(icsText);

function getVEventBlock(text) {
  const start = text.indexOf('BEGIN:VEVENT');
  const end = text.indexOf('END:VEVENT');
  if (start >= 0 && end >= 0) return text.slice(start, end + 10);
  return text;
}
const veventText = getVEventBlock(icsText);

function getICSField(text, field) {
  const lines = text.split(/\r?\n/);
  for (const line of lines) {
    const upper = line.toUpperCase();
    if (upper.startsWith(field + ':') || upper.startsWith(field + ';')) {
      const lastColon = line.lastIndexOf(':');
      return lastColon >= 0 ? line.slice(lastColon + 1).trim() : '';
    }
  }
  return '';
}

function getICSFieldAll(text, field) {
  const lines = text.split(/\r?\n/);
  const results = [];
  for (const line of lines) {
    const upper = line.toUpperCase();
    if (upper.startsWith(field + ':') || upper.startsWith(field + ';')) {
      const lastColon = line.lastIndexOf(':');
      if (lastColon >= 0) results.push(line.slice(lastColon + 1).trim());
    }
  }
  return results;
}

function getCN(text, field) {
  const lines = text.split(/\r?\n/);
  for (const line of lines) {
    const upper = line.toUpperCase();
    if (upper.startsWith(field + ':') || upper.startsWith(field + ';')) {
      const cnMatch = line.match(/CN=([^;:]+)/i);
      return cnMatch ? cnMatch[1].trim() : '';
    }
  }
  return '';
}

function getCNAll(text, field) {
  const lines = text.split(/\r?\n/);
  const results = [];
  for (const line of lines) {
    const upper = line.toUpperCase();
    if (upper.startsWith(field + ':') || upper.startsWith(field + ';')) {
      const cnMatch = line.match(/CN=([^;:]+)/i);
      results.push(cnMatch ? cnMatch[1].trim() : '');
    }
  }
  return results;
}

function parseICSDate(dtStr) {
  if (!dtStr) return null;
  if (dtStr.match(/^\d{4}-\d{2}-\d{2}T/)) return dtStr;
  const val = dtStr.trim();
  if (val.length >= 15) {
    return val.slice(0,4) + '-' + val.slice(4,6) + '-' + val.slice(6,8) + 'T' + val.slice(9,11) + ':' + val.slice(11,13) + ':' + val.slice(13,15);
  } else if (val.length === 8) {
    return val.slice(0,4) + '-' + val.slice(4,6) + '-' + val.slice(6,8) + 'T00:00:00';
  }
  return null;
}

function inferMeetingType(summary) {
  const s = (summary || '').toLowerCase();
  if (s.includes('discovery') || s.includes('intro') || s.includes('initial')) return 'discovery_call';
  if (s.includes('demo') || s.includes('presentation')) return 'demo';
  if (s.includes('debrief') || s.includes('follow')) return 'follow_up';
  if (s.includes('validation') || s.includes('proof')) return 'validation_meeting';
  if (s.includes('negotiat') || s.includes('contract') || s.includes('pricing')) return 'negotiation';
  if (s.includes('kickoff')) return 'kickoff';
  if (s.includes('check') || s.includes('sync') || s.includes('status')) return 'check_in';
  if (s.includes('scoping') || s.includes('scope')) return 'scoping';
  return 'meeting';
}

// Helper: extract domain from email address string
function extractEmailDomain(emailStr) {
  const match = emailStr.match(/<([^>]+)>/) || emailStr.match(/([^\s@]+@[^\s]+)/);
  const addr = match ? match[1] : emailStr;
  const parts = addr.trim().split('@');
  return parts.length === 2 ? parts[1].toLowerCase().replace(/[^a-z0-9.-]/g, '') : '';
}

// Helper: derive company name from domain (strip TLD + common subdomains)
function domainToCompany(domain) {
  if (!domain) return 'Unknown';
  const stripped = domain.replace(/^(mail|smtp|mx|email)\./i, '');
  const parts = stripped.split('.');
  const name = parts.length >= 2 ? parts[parts.length - 2] : parts[0];
  return name.charAt(0).toUpperCase() + name.slice(1);
}

const summary = getICSField(veventText, 'SUMMARY');
const cleanSummary = summary.replace(/^(FW|RE|FWD):\s*/i, '').trim();
const dtStartRaw = getICSField(veventText, 'DTSTART');
const dtEndRaw = getICSField(veventText, 'DTEND');
const dtStart = parseICSDate(dtStartRaw);
const dtEnd = parseICSDate(dtEndRaw);
const location = getICSField(veventText, 'LOCATION');
const description = getICSField(veventText, 'DESCRIPTION').replace(/\\n/g, '\n').slice(0, 1000);
const organizerEmail = getICSField(veventText, 'ORGANIZER').replace('mailto:', '').trim();
const organizerName = getCN(veventText, 'ORGANIZER');
const organizer = organizerName ? organizerName + ' <' + organizerEmail + '>' : organizerEmail;

const attendeeEmails = getICSFieldAll(veventText, 'ATTENDEE').map(v => v.replace('mailto:', '').trim());
const attendeeCNs = getCNAll(veventText, 'ATTENDEE');
const attendees = attendeeEmails.map((email, i) => ({
  email,
  name: attendeeCNs[i] || ''
})).filter(a => {
  const e = a.email.toLowerCase();
  return a.email && a.email.includes('@') &&
    !e.includes('austin.holland') &&
    !e.includes('raustinholland');
});

const meetingType = inferMeetingType(cleanSummary);

// --- Deal attribution override from attendee domain ---
// If the existing deal is 'unknown' or the sender domain was the forwarding account,
// re-derive deal info from the first external attendee's domain.
const internalDomains = ['clearwatersecurity.com', 'gmail.com'];
let resolvedDealId = dealData.deal_id;
let resolvedCompany = dealData.company_name;
let resolvedDomain = dealData.sender_domain;

if (attendees.length > 0) {
  const firstExternal = attendees[0];
  const attendeeDomain = extractEmailDomain(firstExternal.email);
  const isCurrentDomainInternal = internalDomains.some(d => (dealData.sender_domain || '').includes(d));
  const isCurrentDealUnknown = (dealData.deal_id || '').includes('unknown') || resolvedCompany === 'Unknown';

  if (attendeeDomain && (isCurrentDomainInternal || isCurrentDealUnknown)) {
    // Re-derive deal from attendee domain
    const company = domainToCompany(attendeeDomain);
    const slug = attendeeDomain.split('.')[0].toLowerCase().replace(/[^a-z0-9]/g, '_').substring(0, 32);
    const year = new Date().getFullYear();
    resolvedDealId = 'cw_' + slug + '_' + year;
    resolvedCompany = company;
    resolvedDomain = attendeeDomain;
  }
}

const embeddableText = [
  '[CALENDAR EVENT]',
  'Title: ' + cleanSummary,
  'Meeting Type: ' + meetingType,
  'Date: ' + (dtStart || 'Unknown'),
  'Organizer: ' + organizer,
  'Attendees: ' + attendees.map(a => a.name ? a.name + ' <' + a.email + '>' : a.email).join(', '),
  'Location: ' + (location || 'Not specified'),
  'Description: ' + (description || 'None'),
  'Deal: ' + resolvedCompany + ' (' + resolvedDealId + ')',
].join('\n');

return [{
  json: {
    ...dealData,
    deal_id: resolvedDealId,
    qdrant_namespace: resolvedDealId,
    company_name: resolvedCompany,
    sender_domain: resolvedDomain,
    doc_type: 'calendar_invite',
    event_summary: cleanSummary,
    event_start: dtStart || null,
    event_end: dtEnd || null,
    event_location: location || null,
    event_description: description || null,
    event_organizer: organizer || null,
    event_attendees: JSON.stringify(attendees),
    meeting_type: meetingType,
    embeddable_text: embeddableText,
    ics_raw: icsText.slice(0, 2000)
  }
}];

// Merge ICS parsed data into the standard text format expected by
// Code: Contextual Enrichment → Code: Chunk Text → HTTP: Embed Chunk pipeline
// $input here is Postgres: Insert Calendar Event which returns {success:true}
// Pull the actual ICS data from the Parse ICS node
const d = $('Code: Parse ICS').first().json;
return [{
