const d = $input.first().json;

function sq(v) {
  if (v === null || v === undefined) return 'NULL';
  return "'" + String(v).replace(/'/g, "''") + "'";
}

// Parse attendees JSON array and build Postgres TEXT[] literal
let attendeesArr = [];
try {
  const parsed = JSON.parse(d.event_attendees || '[]');
  attendeesArr = parsed.map(a => {
    const label = a.name ? `${a.name} <${a.email}>` : a.email;
    return label;
  });
} catch(e) {}

const attendeesPg = attendeesArr.length > 0
  ? "ARRAY[" + attendeesArr.map(a => "'" + a.replace(/'/g, "''") + "'").join(', ') + "]"
  : "ARRAY[]::text[]";

const googleEventId = d.message_id
  ? d.message_id
  : (d.deal_id + '_' + Date.now());

const descriptionVal = d.event_organizer
  ? sq('Organizer: ' + (d.event_organizer || '') + '\n' + (d.event_description || ''))
  : (d.event_description ? sq(d.event_description) : 'NULL');

const sql = `INSERT INTO calendar_events
  (google_event_id, deal_id, title, description, start_time, end_time, location, attendees, meeting_type, agenda_sent)
VALUES (
  ${sq(googleEventId)},
  ${sq(d.deal_id)},
  ${sq(d.event_summary)},
  ${descriptionVal},
  ${(d.event_start && d.event_start.match(/^\d{4}-\d{2}-\d{2}T/)) ? sq(d.event_start) : 'NULL'},
  ${(d.event_end && d.event_end.match(/^\d{4}-\d{2}-\d{2}T/)) ? sq(d.event_end) : 'NULL'},
  ${d.event_location ? sq(d.event_location) : 'NULL'},
  ${attendeesPg},
  ${sq(d.meeting_type || 'meeting')},
  false
) ON CONFLICT (google_event_id) DO NOTHING`;

return [{ json: { ...d, calendar_insert_sql: sql } }];
